                // mit Multi-Mesh-Group + sin/cos-Animation. Ammo-Body bleibt
                // identisch (rein visuell). Default "human".
                soul: "human",
                // Welle 10b.3 — Mount-State für moveable-Affordance. null
                // wenn Spieler nicht aufgesessen, sonst entry.id der
