                emotionLastApply: {
                    joy: -Infinity,
                    awe: -Infinity,
                    sorrow: -Infinity,
                    hope: -Infinity,
                    peace: -Infinity,
                    chaos: -Infinity,
                },
                emotionApplyCooldown: 30,
                emotionThreshold: 0.7,
                // Welle 6.D Etappe 2 — Boosts: temporäre Tag-Modifikationen.
                // Drei Quellen:
