                const tvar = h01(ai, kk, 6) < 0.5 ? 0 : 1;
                const tuX = kindCol * 0.25;
                const tuY = tvar * 0.5;
                const rot = h01(ai, kk, 5) * Math.PI;
                const cR = Math.cos(rot),
                    sR = Math.sin(rot);
