// erfundene, in sich konsistente Welt-Physik (behauptet nur KONSISTENZ, nie Wahrheit — bleibt,
// aber markiert); „form" = geometrische Stellvertreter (Übergang, bis Ω-L2 die Physik einwebt).
AnazhRealm.AXIS_CLASS = Object.freeze({
    // PHYSIKALISCH — Material-Eigenschaften mit echtem Richter
    härte: "physik",
    dichte: "physik",
    zähigkeit: "physik",
    wärmeleitung: "physik",
    stromleitung: "physik",
    transparent: "physik",
    brennbar: "physik",
    // PHYSIKALISCH — gerechnete Größen (Säule I, Ω-Φ1..Φ5)
    stability: "physik",
    stiffness: "physik",
    balance: "physik",
    leverage: "physik",
    loadSound: "physik",
    rollable: "physik",
    // KONVENTION — AnazhRealms erfundene Welt-Physik (kein physikalischer Richter)
    magieleitung: "konvention",
    resoniert: "konvention",
    lebendig: "konvention",
    // FORM — geometrische Stellvertreter (Übergangs-Fallback, §5 Ω-L1)
    pointedFraction: "form",
    elongation: "form",
    hollowness: "form",
    axialSymmetry: "form",
    spread: "form",
    bodyShape: "form",
    portalShape: "form",
    livingBody: "form",
    rideable: "form",
    bulk: "form",
});
AnazhRealm.AXIS_CLASS_LABEL = Object.freeze({ physik: "gerechnet", konvention: "Welt-Konvention", form: "Form" });
// §7.3(b) (V18.164) — KONJUNKTIONS-Achsen (0/1) sind TATEN, keine Zahlen: die
// WARUM-Führung (_blueprintRoleGapHint) spricht sie als deutsche Handlung aus.
AnazhRealm.AXIS_ACTION_HINTS = Object.freeze({
    rideable: "setze einen Sitz-Anker (Fahrzeug = Sitz + Antrieb)",
    livingBody: "nutze lebendiges Material am Körper",
    bodyShape: "forme einen Körper (symmetrisch · vertikal · Glieder)",
    portalShape: "forme einen Ring in Reisenden-Größe",
    // Ω-W2 (wahrerbauplan §7 — Optimierung an ECHTEN Größen): die GERECHNETEN
    // Physik-Achsen (Säule I) bekommen ihren physik-wahren Verb — der Hinweis
    // zitiert das Gesetz, nicht nur eine Zahl. „verbreitere die Basis → der
    // Schwerpunkt sitzt sicherer im Stützpolygon → stabiler" (BEWEIS: die Tat
    // verschiebt die gerechnete Größe messbar in die versprochene Richtung).
    stability: "verbreitere die Basis (Schwerpunkt sicher über der Standfläche)",
    loadSound: "schließe den Lastpfad zum Boden (kein schwebendes Teil)",
    rollable: "setze runde Räder an den Boden (rollt um eine freie Achse)",
    stiffness: "lege Material weg von der Biegeachse (Hohlrohr/I-Profil statt Vollstab)",
    balance: "verlagere die Masse zum Griff (näher balanciert → schnellere Führung)",
    leverage: "rücke die Kopfmasse nach vorn (längerer Hebel → mehr Wucht)",
});

// S10 (kampf-plan §11.10) — die KATALYSATOR-OP aus der Form: ein Werkzeug katalysiert eine Transformation, und
// seine FORM bestimmt welche. Die opClass emergiert als argmax-Resonanz des Produkt-Vektors (Tags ⊕ pointedFraction)
// gegen diese Signaturen — die physischen Katalyse-Geometrien (an synthetischen Formen GEMESSEN): subtractive = eine
// SCHARFE/spitze Klinge (schneidet/schnitzt; pointedFraction dominiert, damit eine dichte Spitze nicht zu plastic
// kippt); plastic = eine STUMPFE, dichte Masse (schmiedet/schlägt — ein Klotz/Hammer); phaseChange = ein MAGIE-
// leitender Stab (wandelt/imbue; magie schlägt sogar die Spitze einer Helix). EHRLICH: additive (mischen/weben) ist
// FORM-mehrdeutig — ein Mörser und ein Hammer sind stumpf-dichte Zwillinge; die add.-Natur ist FUNKTION, nicht Form
// (wie die Werkstatt-Natur, V17.70). Darum ist additive die schwache Residual-Signatur (weich/zäh/lebendig) — die
// EMERGENZ trägt die drei physischen Klassen; eine reine Misch-Absicht bleibt der Schöpfer-Override (opClass von
// Hand). Die Built-in-Werkzeuge sind FORMLOS → der Wächter ist synthetisch (checkBandV1771).
// V17.90 — die Material-Gewichte für die NORMALISIERTE Skala angehoben (A1: dichte/magieleitung jetzt [0..1]
// statt [0..3]). Sonst schlüge die unveränderte pointedFraction (subtractive) die material-getriebenen Klassen
// (plastic/phaseChange) zu oft (eine magie-Helix las subtractive statt phaseChange). pointedFraction bleibt
// [0..1], also keine Anhebung; die Balance scharf→subtractive / stumpf-dicht→plastic / magie→phaseChange GEMESSEN.
AnazhRealm.OP_CLASS_SIGNATURES = Object.freeze({
    subtractive: Object.freeze({ pointedFraction: 2.3, härte: 0.2 }),
    plastic: Object.freeze({ dichte: 1.8, härte: 0.5 }),
    phaseChange: Object.freeze({ magieleitung: 3.0 }),
    additive: Object.freeze({ zähigkeit: 1.5, lebendig: 1.5, härte: -1.0 }),
});
// Der Standard-opName je opClass (die opChain-„Geschichte"; die opClass treibt die Material-Kompatibilität).
AnazhRealm.OP_NAME_BY_CLASS = Object.freeze({
    subtractive: "carve",
    plastic: "forge",
    phaseChange: "imbue",
    additive: "mix",
});

