AnazhRealm.CREATURE_SPAWN_FAR_MIN = 130; // V18.315 — Boot-Kreaturen spawnen ≥130 m fern (im Nebel): die Haut backt off-thread unsichtbar, sie tauchen schon-fertig aus der Distanz auf (kein Pop/Freeze in Sicht)
AnazhRealm.RING_RAMP_START = 2; // Start-Ring beim Boot (5×5 = 25 Chunks ≈ 108 m, Nebel nah)
AnazhRealm.RING_RAMP_SETTLE_MS = 350; // der „Atem" zwischen zwei Ring-Wachstums-Schritten
// V18.313 — DAS ERWACHEN: solange noch KEIN Boden-Chunk steht (nur die Spawn-Plattform,
// `_builtRingRadius() < 0`), umhüllt der Lade-Nebel den Spieler ENG (Kokon, ~14 m Sicht) —
// wie das Erwachen aus dem Schlaf: die Welt ist verborgen, die fernen Spawns unsichtbar; sie
// enthüllt sich, sobald der Boden erscheint (der Nebel weitet ring-gekoppelt, exp-geglättet).
AnazhRealm.AWAKEN_FOG_FAR = 14;
// V18.324 — der Mindestabstand zwischen zwei Sky-Env-PMREM-Regenerierungen (Wall-Clock). Die
// Tag-Nacht-Uhr + eine Emotion (skybox_color → skyTint-Cross-Fade über ~45 s) driften die
// Himmelsfarbe → die Env regeneriert (V18.322 identitäts-stabil, kein Recompile-Cascade mehr,
// ABER jede Regenerierung rendert einen PMREM-Pass). Bei 2 s feuerte das ~22× über den 45-s-
// Cross-Fade = die wahrscheinlichste Wurzel des „kurzen Freeze bei Emotion" (der PMREM-Render
// kostet auf schwacher GPU). 6 s deckelt das auf ~7× — die IBL-Reflexion auf Metallen ein paar
// Sekunden nachlaufen zu lassen ist unmerklich (sie ist ein weicher Sekundär-Effekt).
AnazhRealm.SKY_ENV_REGEN_MIN_MS = 6000;
// V18.306 — der Frame muss SO LANGE anhaltend über Budget sein, bevor der Ring eine Schale
// zurückgibt: lang genug, dass ein transienter Bau-/Carve-Spike (< 200 ms) NICHT schrumpft,
// kurz genug, dass echte Dauerlast (Freeze) den Ring zügig auf die haltbare Größe senkt.
AnazhRealm.RING_SHRINK_SUSTAIN_MS = 1200;
// V18.318 — DIE WACHS-HYSTERESE (Schöpfer „der Kreis soll NICHT bei Überlast ausweiten"): der
// Ring wächst erst, wenn der Frame ANHALTEND Kopfraum hat — länger als die Schrumpf-Hysterese,
// damit die Welt im Zweifel KLEIN + stabil bleibt (Wachsen ist zaghaft, Schrumpfen beherzt). So
// ratscht ein transienter leichter Boot-Frame den Ring NICHT mehr hoch, bevor das Laub lädt.
AnazhRealm.RING_GROW_SUSTAIN_MS = 1500;
// V18.277 — DIE KAPAZITÄTS-GEWACHSENE DICHTE (Schöpfer „Deko steigt bei Kapazität"): die
// Schwester des `foliageRadius`. Wo der Radius die REICHWEITE der Vegetation nach Kapazität
