// Spieler ohne Sprung aufsteigt.
AnazhRealm.PLAYER_FOOT_OFFSET = 0.5;
AnazhRealm.PLAYER_STEP_UP = 0.6;
// Boden-Haftung: bis zu dieser Distanz UNTER den Füßen klebt der Läufer am Boden (snap-
